member.example:
Bind the Image sprite property using a serialized binder field — the target Image is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ImageSpriteBinder _icon;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Sprite _icon;
    }


Bind the Image sprite property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Image _image;
        
        private ImageSpriteBinder Icon =>
            new(_image);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Sprite _icon;
    }

Switch the Image sprite between two values using a serialized binder field — the target Image is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ImageSpriteSwitcherBinder _isSelected;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isSelected;
    }


Switch the Image sprite between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private Image _image;
        
        [SerializeField]
        private Sprite _selectedSprite;
        
        [SerializeField]
        private Sprite _defaultSprite;
        
        private ImageSpriteSwitcherBinder IsSelected => new(
            _image, _selectedSprite, _defaultSprite);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isSelected;
    }
